module.render:
const deg = parseFloat(args.angle);
const a = ((Number.isFinite(deg) ? deg : 40) * Math.PI) / 180;
const color = args.color || 'var(--accent-color)';
const C = 60, R = 46;
const x = C + R * Math.cos(a), y = C - R * Math.sin(a);
const f = (v) => v.toFixed(2);
// axes + circle
let svg = `<line x1="4" y1="${C}" x2="116" y2="${C}" class="mdp-uc-axis"/>` +
  `<line x1="${C}" y1="4" x2="${C}" y2="116" class="mdp-uc-axis"/>` +
  `<circle cx="${C}" cy="${C}" r="${R}" class="mdp-uc-circle"/>`;
// cos (horizontal) and sin (vertical) segments
svg += `<line x1="${C}" y1="${C}" x2="${f(x)}" y2="${C}" class="mdp-uc-cos"/>` +
  `<line x1="${f(x)}" y1="${C}" x2="${f(x)}" y2="${f(y)}" class="mdp-uc-sin"/>`;
// radius + point
svg += `<line x1="${C}" y1="${C}" x2="${f(x)}" y2="${f(y)}" class="mdp-uc-radius"/>` +
  `<circle cx="${f(x)}" cy="${f(y)}" r="2" class="mdp-uc-pt"/>`;
// angle arc (from +x axis counter-clockwise to a)
const r0 = 13;
const large = Math.abs(a) % (2 * Math.PI) > Math.PI ? 1 : 0;
const sweep = a >= 0 ? 0 : 1;
svg += `<path d="M${C + r0},${C} A${r0},${r0} 0 ${large} ${sweep} ${f(C + r0 * Math.cos(a))},${f(C - r0 * Math.sin(a))}" class="mdp-uc-arc"/>`;
const mid = a / 2;
svg += `<text x="${f(C + (r0 + 6) * Math.cos(mid))}" y="${f(C - (r0 + 6) * Math.sin(mid))}" class="mdp-uc-theta" text-anchor="middle" dominant-baseline="middle">θ</text>`;
// labels
const showVals = String(args.values) === 'true';
const sinLbl = showVals ? Math.sin(a).toFixed(3) : 'sin θ';
const cosLbl = showVals ? Math.cos(a).toFixed(3) : 'cos θ';
const sinAnchor = Math.cos(a) >= 0 ? 'start' : 'end';
svg += `<text x="${f(x + (Math.cos(a) >= 0 ? 3 : -3))}" y="${f((C + y) / 2)}" class="mdp-uc-lbl mdp-uc-lbl-sin" text-anchor="${sinAnchor}" dominant-baseline="middle">${sinLbl}</text>`;
svg += `<text x="${f((C + x) / 2)}" y="${f(C + (Math.sin(a) >= 0 ? 8 : -5))}" class="mdp-uc-lbl mdp-uc-lbl-cos" text-anchor="middle">${cosLbl}</text>`;
const sinColor = (args.sincolor || '#dc2626').trim() || '#dc2626';
const cosColor = (args.coscolor || '#2563eb').trim() || '#2563eb';
const maxW = (args.maxwidth || '320px').trim() || '320px';
return `\n\n<div class="mdp-mod-unitcircle" style="--uc-c:${color}; --uc-sin:${sinColor}; --uc-cos:${cosColor}; --uc-mw:${maxW};"><svg viewBox="0 0 120 120" preserveAspectRatio="xMidYMid meet">${svg}</svg></div>\n\n`;
